Use **`WebApplicationFactory<TEntryPoint>`** from `Microsoft.AspNetCore.Mvc.Testing`. It hosts your app in-memory and gives you an `HttpClient` — no port, no real server.

### 1. Add the package

```bash
dotnet add tests/MyMcp.Tests/MyMcp.Tests.csproj package Microsoft.AspNetCore.Mvc.Testing
```

### 2. Create a fixture

```csharp
using Microsoft.AspNetCore.Mvc.Testing;

public class McpTestFixture : WebApplicationFactory<Program>
{
    // Override ConfigureWebHost if you need to swap services:
    // protected override void ConfigureWebHost(IWebHostBuilder builder)
    // {
    //     builder.ConfigureServices(services => { /* replace deps */ });
    // }
}
```

### 3. Write MCP protocol tests

MCP over HTTP uses **JSON-RPC 2.0** via `POST`. A typical test sends `initialize`, then calls a tool/resource:

```csharp
using System.Net.Http.Json;
using System.Text.Json;
using Xunit;

public class McpProtocolTests : IClassFixture<McpTestFixture>
{
    private readonly HttpClient _client;

    public McpProtocolTests(McpTestFixture fixture)
    {
        _client = fixture.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);
        response.EnsureSuccessStatusCode();

        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.True(body.TryGetProperty("result", out var result));
        Assert.True(result.TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first (required by MCP spec)
        await InitializeAsync();

        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };

        var response = await _client.PostAsJsonAsync("/mcp", request);
        response.EnsureSuccessStatusCode();

        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    private async Task InitializeAsync()
    {
        var init = new
        {
            jsonrpc = "2.0", id = 0, method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };
        var resp = await _client.PostAsJsonAsync("/mcp", init);
        resp.EnsureSuccessStatusCode();
    }
}
```

### Key points

- **No real port** — `WebApplicationFactory` uses an in-memory `TestServer`.
- **Full pipeline** — middleware, routing, DI all run exactly as in production.
- Adjust the endpoint path (`/mcp`) to match your server's route.
- For **SSE (Streamable HTTP)**, read the response stream with `ReadAsStreamAsync()` and parse `text/event-stream` lines.
- Use `ConfigureWebHost` to swap external dependencies (databases, API clients) with fakes.
